#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00390Custom {
public:
    __aicore__ inline KernelCa6k00390Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t groups, uint32_t N, uint32_t C,
                                uint32_t H, uint32_t W)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        groups_ = groups;
        N_ = N;
        C_ = C;
        H_ = H;
        W_ = W;
        chPerGroup_ = C_ / groups_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueue_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        while (base < totalLen_) {
            uint32_t curLen = totalLen_ - base;
            if (curLen > tileLen_) curLen = tileLen_;
            ProcessTile(base, curLen);
            base += strideElems;
        }
    }

private:
    __aicore__ inline void ProcessTile(uint32_t base, uint32_t len)
    {
        // Read contiguous input tile into local tensor
        AscendC::LocalTensor<float> xLocal = inQueue_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[base], len);
        inQueue_.EnQue(xLocal);

        xLocal = inQueue_.DeQue<float>();

        // For each element in the tile, compute shuffled output index and write
        for (uint32_t i = 0; i < len; i++) {
            uint32_t inIdx = base + i;

            // Compute input spatial coordinates
            uint32_t n = inIdx / (C_ * H_ * W_);
            uint32_t rem1 = inIdx % (C_ * H_ * W_);
            uint32_t c_in = rem1 / (H_ * W_);
            uint32_t rem2 = rem1 % (H_ * W_);
            uint32_t h = rem2 / W_;
            uint32_t w = rem2 % W_;

            // Output channel after shuffle
            uint32_t c_out = (c_in % groups_) * chPerGroup_ + (c_in / groups_);

            // Output linear index
            uint32_t outIdx = n * C_ * H_ * W_ + c_out * H_ * W_ + h * W_ + w;

            // Get value from local input tile
            float val = xLocal(i);

            // Write to output global using a temporary local scalar
            AscendC::LocalTensor<float> tmp = tmpBuf_.AllocTensor<float>();
            tmp(0) = val;
            AscendC::DataCopy(yGm_[outIdx], tmp, 1);
            tmpBuf_.FreeTensor(tmp);
        }

        inQueue_.FreeTensor(xLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t groups_ {2};
    uint32_t N_ {1};
    uint32_t C_ {1};
    uint32_t H_ {1};
    uint32_t W_ {1};
    uint32_t chPerGroup_ {1};
};

extern "C" __global__ __aicore__ void ca6k00390_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00390Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.groups, tiling_data.N, tiling_data.C, tiling_data.H, tiling_data.W);
    op.Process();
}
